import{_ as t}from"./chunks/13-tui-run-assessment.BB6BYCVS.js";import{_ as s,o as a,c as n,a2 as r}from"./chunks/framework.DTa47_fH.js";const g=JSON.parse('{"title":"Run Assessment","description":"","frontmatter":{},"headers":[],"relativePath":"assessment/index.md","filePath":"assessment/index.md"}'),o={name:"assessment/index.md"};function i(d,e,l,m,u,c){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="run-assessment" tabindex="-1">Run Assessment <a class="header-anchor" href="#run-assessment" aria-label="Permalink to &quot;Run Assessment&quot;">​</a></h1><p>SWAO supports five assessment types, each targeting a different subject. Two are available today; three are on the roadmap.</p><p>Access from the TUI main menu by pressing <strong>3</strong>, then select the assessment type.</p><p><img src="'+t+'" alt="SWAO assessment type selection"></p><table tabindex="0"><thead><tr><th>#</th><th>Assessment type</th><th>Status</th><th>Subject</th></tr></thead><tbody><tr><td>[1]</td><td><a href="./application">Application Assessment</a></td><td>Available</td><td>Cloud application source code</td></tr><tr><td>[2]</td><td><a href="./audit">Audit Assessment</a></td><td>Coming soon</td><td>Human-led compliance audit</td></tr><tr><td>[3]</td><td><a href="./landing-zone">Landing Zone Assessment</a></td><td>Available</td><td>Cloud infrastructure configuration</td></tr><tr><td>[4]</td><td><a href="./llm">LLM Assessment</a></td><td>Coming soon</td><td>AI model sovereignty benchmarking</td></tr><tr><td>[5]</td><td><a href="./hybrid">Hybrid Assessment</a></td><td>Coming soon</td><td>Combined source + human evidence</td></tr></tbody></table><hr><h2 id="how-assessment-works" tabindex="-1">How assessment works <a class="header-anchor" href="#how-assessment-works" aria-label="Permalink to &quot;How assessment works&quot;">​</a></h2><p>Every assessment type shares the same pipeline:</p><ol><li><strong>Input reading</strong> -- SWAO reads your application source, configuration files, and any context documents you have placed in the ingestion folder.</li><li><strong>Pass execution</strong> -- a sequence of analysis passes runs against the input. Some passes use static analysis (deterministic, no LLM required); others invoke your configured LLM to derive findings that require language understanding.</li><li><strong>Signal emission</strong> -- each pass emits signals: structured findings with a signal ID, severity, compliance control mapping, rationale text, and evidence references.</li><li><strong>Output generation</strong> -- signals are aggregated into the Workspace Signal Pack (WSP), from which SWAO generates reports, the BI export bundle, and the HTML publication.</li></ol><p>All outputs are stored in <code>apps/&lt;app-id&gt;/wsp/</code> and can be regenerated at any time from the same signal set without re-running the assessment.</p><hr><h2 id="after-assessment" tabindex="-1">After assessment <a class="header-anchor" href="#after-assessment" aria-label="Permalink to &quot;After assessment&quot;">​</a></h2><p>Once assessment completes, use the other TUI menu items to turn results into deliverables:</p><ul><li><strong>[4] Generate Report</strong> -- text and Markdown audit report</li><li><strong>[5] Publish HTML</strong> -- self-contained HTML publication for the client</li><li><strong>[6] Export BI</strong> -- star schema bundle for Power BI or Tableau</li></ul>',14)])])}const f=s(o,[["render",i]]);export{g as __pageData,f as default};
